import React, { useState } from 'react';

const App = () => {
  const [categories, setCategories] = useState(['Category 1', 'Category 2', 'Category 3']);
  const [selectedCategory, setSelectedCategory] = useState('Category 1');
  const [filteredContent, setFilteredContent] = useState([]);

  const handleCategoryChange = (category) => {
    setSelectedCategory(category);
  };

  const handleFilterChange = (tag) => {
    const filteredContent = categories[selectedCategories.indexOf(selectedCategory)].filter(item => item.tags.includes(tag));
    setFilteredContent(filteredContent);
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="w-full max-w-md p-4 bg-white rounded shadow sm:p-6 md:p-8">
        <h2 className="text-lg font-bold leading-6 text-gray-900">Categories</h2>
        <div className="mt-4 grid grid-cols-1 gap-y-6 sm:grid-cols-2 lg:grid-cols-3">
          {categories.map((category, index) => (
            <button
              key={index}
              className="w-full px-4 py-2 text-sm font-medium text-gray-700 bg-white border border-gray-300 rounded-md shadow-sm hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-gray-500"
              onClick={() => handleCategoryChange(category)}
              style={{
                backgroundColor: selectedCategory === category ? '#C06C88' : '#B7D7CD',
                color: selectedCategory === category ? '#FFFFFF' : '#000000'
              }}
            >{category}</button>
          ))}
        </div>
        <div className="mt-4">
          <h2 className="text-lg font-bold leading-6 text-gray-900">Filter</h2>
          <div className="mt-4 grid grid-cols-1 gap-y-6 sm:grid-cols-2 lg:grid-cols-3">
            <button className="w-full px-4 py-2 text-sm font-medium text-gray-700 bg-white border border-gray-300 rounded-md shadow-sm hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-gray-500" onClick={() => handleFilterChange('Tag 1')}>Tag 1</button>
            <button className="w-full px-4 py-2 text-sm font-medium text-gray-700 bg-white border border-gray-300 rounded-md shadow-sm hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-gray-500" onClick={() => handleFilterChange('Tag 2')}>Tag 2</button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;
